arguments.newText:
for ep in endpoints:
    try:
        resp = client.get(ep)
        data = resp.json()
        print(f'\n{ep}:')
        print(f'  code: {data.get("code")}')
        msg = data.get("message", "")[:50]
        print(f'  message: {msg}')
        zpdata = data.get('zpData', {})
        if zpdata:
            print(f'  zpData keys: {list(zpdata.keys())[:10]}')
            if 'friendList' in zpdata:
                print(f'  friendList count: {len(zpdata.get("friendList", []))}')
                # 打印第一条
                if zpdata['friendList']:
                    print(f'  first friend: {json.dumps(zpdata["friendList"][0], ensure_ascii=False)[:200]}')
    except Exception as e:
        print(f'\n{ep}: error - {e}')

