request.fn:
() => {
  // 尝试用更精确的方式找到并点击张先生
  // 先找到所有聊天列表项
  const allElements = document.querySelectorAll('*');

  // 查找包含"张先生"的可点击元素
  let target = null;
  for (const el of allElements) {
    if (el.textContent === '张先生' && el.tagName !== 'SCRIPT') {
      // 向上找可点击的父元素
      let parent = el;
      for (let i = 0; i < 10; i++) {
        if (!parent) break;
        const style = window.getComputedStyle(parent);
        if (style.cursor === 'pointer') {
          target = parent;
          break;
        }
        parent = parent.parentElement;
      }
      if (target) break;
    }
  }

  if (target) {
    target.click();
    console.log('Clicked on Zhang successfully');
    return 'clicked';
  }

  // 备用方案：用 keyboard 选择
  const searchInput = document.querySelector('input[placeholder*=\'30天\']');
  if (searchInput) {
    searchInput.focus();
    console.log('Focused search input');
  }

  return 'not found';
}

