() => {
  // 查找输入框
  const inputs = document.querySelectorAll('textarea, input[type=\'text\'], input[type=\'input\']');
  console.log('Found inputs:', inputs.length);

  // 尝试多种定位方式
  let input = document.querySelector('textarea[placeholder*=\'发送\']') || 
              document.querySelector('textarea') ||
              document.querySelector('input[placeholder*=\'发\']');

  if (input) {
    console.log('Input found:', input.tagName);
    input.focus();
    input.value = '没有';

    // 触发 input 事件
    input.dispatchEvent(new Event('input', { bubbles: true }));

    // 尝试发送 - 按 Enter
    const event = new KeyboardEvent('keydown', {
      key: 'Enter',
      code: 'Enter',
      keyCode: 13,
      which: 13,
      bubbles: true
    });
    input.dispatchEvent(event);

    return 'sent';
  }

  // 如果没找到，显示页面结构
  console.log('Page structure:');
  console.log(document.body.innerHTML.substring(0, 500));

  return 'not found';
}

