() => {
  // 检查所有 iframe
  const iframes = document.querySelectorAll('iframe');
  console.log('Iframes:', iframes.length);

  for (let i = 0; i < iframes.length; i++) {
    const iframe = iframes[i];
    console.log(`Iframe ${i}:`, iframe.src, iframe.id, iframe.className);

    try {
      const doc = iframe.contentDocument || iframe.contentWindow.document;
      const inputs = doc.querySelectorAll('textarea');
      console.log(`  Inputs in iframe ${i}:`, inputs.length);

      if (inputs.length > 0) {
        console.log('  Found input in iframe', i);
        inputs[0].value = '没有';
        inputs[0].dispatchEvent(new Event('input', { bubbles: true }));

        // 尝试按 Enter 发送
        inputs[0].dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', bubbles: true }));
        return 'found in iframe ' + i;
      }
    } catch (e) {
      console.log('  Cannot access iframe', i, e.message);
    }
  }

  return 'not found in iframes';
}

